DELETE ca
FROM cursanteaula ca
JOIN aula a ON a.id = ca.aulaId
JOIN cohorte c ON c.id = a.cohorteId
JOIN postitulo p ON p.id = c.postituloId
WHERE p.codigo IN ('EI','EyCD','EA','IB')
  AND c.anio IN (2025,2026);

DELETE FROM inscripto WHERE cohorteId IN (7,8,9,10,11,12,13,14);

DELETE FROM cursante WHERE dni LIKE '77%';

